 * @param id - ID a validar
 * @returns Mensaje de error o null si es v├ílido
 */
export function validateClinicalMedicationId(id: string | number): string | null {
    if (id === null || id === undefined) {
        return 'El ID del medicamento cl├¡nico es requerido.';
    }

    if (typeof id === 'string') {
        if (!id.trim()) {
            return 'El ID del medicamento cl├¡nico no puede estar vac├¡o.';
        }

        // Intentar convertir a n├║mero si es string num├®rico
        const numId = parseInt(id, 10);
        if (isNaN(numId) || numId <= 0) {
            return 'El ID del medicamento cl├¡nico debe ser un n├║mero v├ílido.';
        }
    } else if (typeof id === 'number') {
        if (id <= 0) {
            return 'El ID del medicamento cl├¡nico debe ser un n├║mero positivo.';
        }
    } else {
        return 'El ID del medicamento cl├¡nico debe ser un n├║mero o string num├®rico.';
    }

    return null; // ID v├ílido
}

