        'update': 'Error al actualizar el registro m├®dico.',
        'delete': 'Error al eliminar el registro m├®dico.',
    };

    const baseMessage = operationMessages[operation] || 'Error en la operaci├│n del registro m├®dico.';

    if (error instanceof Error) {
