        case OlderAdultFamilyValidationError.INVALID_RELATIONSHIP:
            return 'Relaci├│n familiar inv├ílida. Debe ser uno de: spouse, child, parent, sibling, grandchild, grandparent, aunt_uncle, niece_nephew, cousin, in_law, other';

        case OlderAdultFamilyValidationError.INVALID_PHONE:
            return 'Tel├®fono inv├ílido. Debe ser un n├║mero v├ílido con al menos 7 d├¡gitos';

        case OlderAdultFamilyValidationError.INVALID_EMAIL:
            return 'Email inv├ílido. Debe tener un formato v├ílido';

        case OlderAdultFamilyValidationError.INVALID_ADDRESS:
            return 'Direcci├│n inv├ílida. Debe tener entre 10 y 500 caracteres';

