// Validaciones de negocio para cambio de contrase├▒a
export function validateChangePasswordData(data: UserChangePasswordData): string | null {
  if (!data || typeof data !== 'object') {
    return 'Error interno: los datos de cambio de contrase├▒a no son v├ílidos.';
  }

  // Validar contrase├▒a actual
  if (!data.currentPassword || typeof data.currentPassword !== 'string') {
    return 'La contrase├▒a actual es requerida.';
  }
  if (data.currentPassword.trim() !== data.currentPassword) {
    return 'La contrase├▒a actual no debe tener espacios al inicio o final.';
  }
  if (data.currentPassword.length < 1) {
    return 'La contrase├▒a actual no puede estar vac├¡a.';
  }

  // Validar nueva contrase├▒a
  if (!data.newPassword || typeof data.newPassword !== 'string') {
    return 'La nueva contrase├▒a es requerida.';
  }
  if (data.newPassword.trim() !== data.newPassword) {
    return 'La nueva contrase├▒a no debe tener espacios al inicio o final.';
  }
  if (data.newPassword.length < 8) {
    return 'La nueva contrase├▒a debe tener al menos 8 caracteres.';
  }
  if (data.newPassword.length > 100) {
    return 'La nueva contrase├▒a es demasiado larga.';
  }
  if (/^\d+$/.test(data.newPassword)) {
    return 'La nueva contrase├▒a no puede ser solo n├║meros.';
  }
  if (/^[a-zA-Z]+$/.test(data.newPassword)) {
    return 'La nueva contrase├▒a debe contener al menos un n├║mero.';
  }
  if (data.newPassword.toLowerCase() === 'password' || data.newPassword === '123456' || data.newPassword === 'contrase├▒a') {
    return 'La nueva contrase├▒a es demasiado com├║n. Elige una m├ís segura.';
  }

  // Verificar que no sea igual a la contrase├▒a actual
  if (data.currentPassword === data.newPassword) {
    return 'La nueva contrase├▒a no puede ser igual a la contrase├▒a actual.';
  }

  return null;
}


// Reglas de red/Axios para perfil
function isNetworkError(error: any): boolean {
  return (
    error?.code === 'ERR_NETWORK' ||
    error?.message === 'Network Error' ||
    error?.isAxiosError && !error.response
  );
}

export function getProfileErrorMessage(error: any): string {
  if (isNetworkError(error)) {
    return 'No se pudo conectar con el servidor. Verifica tu conexi├│n de red o que el backend est├® disponible.';
  }
  if (error?.response?.status === 400) {
    const msg = error?.response?.data?.message;
    if (typeof msg === 'string') return msg;
    if (Array.isArray(msg)) return msg.join(' ');
    return 'Datos enviados no v├ílidos.';
  }
  if (error?.response?.status === 401) {
    return 'No autorizado. Verifica que est├®s autenticado.';
  }
  if (error?.response?.status === 403) {
    return 'No tienes permisos para realizar esta acci├│n.';
  }
  if (error?.response?.status === 404) {
    return 'Perfil no encontrado.';
  }
  if (error?.response?.status === 409) {
    return 'Conflicto de datos. Es posible que el email ya est├® en uso.';
  }
  if (error?.response?.status === 422) {
    return 'Datos inv├ílidos. Verifica la informaci├│n proporcionada.';
  }
  if (error?.response?.status === 429) {
    return 'Demasiados intentos. Espera unos minutos antes de volver a intentar.';
  }
  if (error?.response?.status >= 500) {
    return 'Error interno del servidor. Intenta m├ís tarde o contacta al soporte.';
  }
  if (error?.response?.data?.message) {
    return error.response.data.message;
  }
  return 'Error desconocido en la gesti├│n del perfil. Intenta nuevamente.';
}

