// Validaciones de negocio para c├│digos TOTP
export function validateTOTPFCode(code: string): string | null {
  if (typeof code !== 'string') {
    return 'Error interno: el c├│digo no es v├ílido.';
  }
  const cleanCode = code.replace(/[\s-]/g, '');
  if (!cleanCode) {
    return 'El c├│digo TOTP es requerido.';
  }
  if (code !== code.trim()) {
    return 'El c├│digo no debe tener espacios al inicio o final.';
  }
  if (cleanCode.length !== code.length) {
    return 'El c├│digo no debe contener espacios ni guiones.';
  }
  if (!/^[0-9]+$/.test(cleanCode)) {
    return 'El c├│digo TOTP solo debe contener n├║meros.';
  }
  if (cleanCode.length !== 6) {
    return 'El c├│digo TOTP debe tener exactamente 6 d├¡gitos.';
  }
  if (/^(.)\1+$/.test(cleanCode)) {
    return 'El c├│digo TOTP no puede ser una secuencia repetida.';
  }
  return null;
}


// Validaciones de negocio para c├│digos de respaldo
export function validateBackupCode(code: string): string | null {
  if (typeof code !== 'string') {
    return 'Error interno: el c├│digo de respaldo no es v├ílido.';
  }
  const cleanCode = code.replace(/[\s-]/g, '');
  if (!cleanCode) {
    return 'El c├│digo de respaldo es requerido.';
  }
  if (code !== code.trim()) {
