  }
  if (!/^[0-9]+$/.test(cleanCode)) {
    return 'El c├│digo de respaldo solo debe contener n├║meros.';
  }
  if (cleanCode.length !== 8) {
    return 'El c├│digo de respaldo debe tener exactamente 8 d├¡gitos.';
