// Reglas de red/Axios para 2FA
function isNetworkError(error: AxiosError | Error | unknown): boolean {
  return (
    (error as any)?.code === 'ERR_NETWORK' ||
    (error as any)?.message === 'Network Error' ||
    (error as any)?.isAxiosError && !(error as any).response
  );
}

export function getTwoFactorErrorMessage(error: AxiosError | Error | unknown): string {
  if (isNetworkError(error)) {
    return 'No se pudo conectar con el servidor. Verifica tu conexi├│n de red o que el backend est├® disponible.';
  }
  const axiosError = error as AxiosError<{ message?: string | string[] }>;
  const data = axiosError?.response?.data as { message?: string | string[] } | undefined;
  if (axiosError?.response?.status === 400) {
    const msg = data?.message;
    if (typeof msg === 'string') return msg;
    if (Array.isArray(msg)) return msg.join(' ');
    return 'C├│digo inv├ílido o expirado.';
  }
  if (axiosError?.response?.status === 401) {
    const msg = Array.isArray(data?.message) ? data?.message.join(' ') : data?.message ?? '';
    if (msg.includes('Token temporal') || msg.includes('expirado')) {
      return 'El tiempo para verificar el c├│digo ha expirado. La hora del servidor puede estar desincronizada.';
    }
    return 'Sesi├│n expirada, por favor inicia sesi├│n nuevamente.';
  }
  if (axiosError?.response?.status === 403) {
    return 'No tienes permisos para realizar esta acci├│n.';
  }
  if (axiosError?.response?.status === 404) {
    return 'Recurso no encontrado o sesi├│n expirada.';
  }
  if (axiosError?.response?.status === 409) {
    return 'Conflicto de datos. Es posible que el 2FA ya est├® configurado.';
  }
  if (axiosError?.response?.status === 422) {
    return 'Datos inv├ílidos. Verifica la informaci├│n proporcionada.';
  }
  if (axiosError?.response?.status === 429) {
    return 'Demasiados intentos de verificaci├│n. Espera unos minutos antes de volver a intentar.';
  }
  if (axiosError?.response?.status && axiosError.response.status >= 500) {
    return 'Error interno del servidor. Intenta m├ís tarde o contacta al soporte.';
  }
  if (data?.message) {
    return Array.isArray(data.message) ? data.message.join(' ') : data.message;
  }
  return 'Error desconocido en la autenticaci├│n de dos factores. Intenta nuevamente.';
}

