    } finally { setSaving(false); }
  };

  if (loading) return <div className="text-center py-5"><div className="spinner-border text-primary"></div></div>;

  return (
    <div className="container py-4" style={{ maxWidth: 600 }}>
      <div className="d-flex align-items-center mb-4 gap-3">
        <button className="btn btn-outline-secondary" onClick={() => navigate('/clinical-medication')} type="button"><i className="bi bi-arrow-left me-1"></i>Regresar</button>
        <h2 className="mb-0"><i className="bi bi-capsule me-2 text-warning"></i>Editar Medicamento Cl├¡nico</h2>
      </div>
      {error && <div className="alert alert-danger"><i className="bi bi-exclamation-triangle-fill me-2"></i>{error}</div>}
      {success && <div className="alert alert-success"><i className="bi bi-check-circle-fill me-2"></i>{success}</div>}
      <div className="card shadow-sm">
        <div className="card-body">
          <form onSubmit={handleSubmit}>
            <div className="mb-3">
              <label className="form-label fw-semibold">Medicamento</label>
              <input name="mMedication" className="form-control" value={form.mMedication ?? ''} onChange={handleChange} disabled={saving} maxLength={500} />
            </div>
            <div className="mb-3">
              <label className="form-label fw-semibold">Dosis</label>
              <input name="mDosage" className="form-control" value={form.mDosage ?? ''} onChange={handleChange} disabled={saving} maxLength={200} />
            </div>
            <div className="mb-3">
              <label className="form-label fw-semibold">Tipo de Tratamiento</label>
              <select name="mTreatmentType" className="form-select" value={form.mTreatmentType ?? ''} onChange={handleChange} disabled={saving}>
                <option value="">ÔÇö Seleccionar ÔÇö</option>
                <option value="temporary">Temporal</option>
                <option value="chronic">Cr├│nico</option>
                <option value="preventive">Preventivo</option>
                <option value="other">Otro</option>
              </select>
            </div>
            <div className="mb-4">
              <label className="form-label fw-semibold">ID Historia Cl├¡nica</label>
              <input type="number" className="form-control" value={form.idClinicalHistory ?? ''} onChange={e => setForm(p => ({ ...p, idClinicalHistory: e.target.value ? Number(e.target.value) : undefined }))} disabled={saving} />
            </div>
            <div className="d-flex gap-2 justify-content-end">
              <button type="button" className="btn btn-outline-secondary" onClick={() => navigate('/clinical-medication')} disabled={saving}>Cancelar</button>
              <button type="submit" className="btn btn-warning" disabled={saving}>{saving ? <><span className="spinner-border spinner-border-sm me-2"></span>Guardando...</> : <><i className="bi bi-save me-2"></i>Actualizar</>}</button>
            </div>
          </form>
        </div>
      </div>
    </div>
  );
}

import { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { emergencyContactService } from '../../../services/emergencyContactService';
import type { CreateEmergencyContactDto } from '../../../services/emergencyContactService';

const initial: CreateEmergencyContactDto = { enPhoneNumber: '', idOlderAdult: undefined };

export default function CreateEmergencyContactPage() {
  const [form, setForm] = useState<CreateEmergencyContactDto>(initial);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [success, setSuccess] = useState('');
  const navigate = useNavigate();

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!form.enPhoneNumber.trim()) { setError('El n├║mero de tel├®fono es requerido'); return; }
    setLoading(true); setError(''); setSuccess('');
    try {
      await emergencyContactService.create(form);
      setSuccess('Contacto de emergencia creado exitosamente');
      setTimeout(() => navigate('/emergency-contacts'), 1500);
    } catch (err: any) {
      const msg = err?.response?.data?.message ?? err?.message ?? 'Error al crear';
      setError(Array.isArray(msg) ? msg.join(', ') : msg);
    } finally { setLoading(false); }
  };

  return (
    <div className="container py-4" style={{ maxWidth: 500 }}>
      <div className="d-flex align-items-center mb-4 gap-3">
        <button className="btn btn-outline-secondary" onClick={() => navigate('/emergency-contacts')} type="button"><i className="bi bi-arrow-left me-1"></i>Regresar</button>
        <h2 className="mb-0"><i className="bi bi-telephone-plus me-2 text-danger"></i>Nuevo Contacto de Emergencia</h2>
      </div>
      {error && <div className="alert alert-danger"><i className="bi bi-exclamation-triangle-fill me-2"></i>{error}</div>}
      {success && <div className="alert alert-success"><i className="bi bi-check-circle-fill me-2"></i>{success}</div>}
      <div className="card shadow-sm">
        <div className="card-body">
          <form onSubmit={handleSubmit}>
            <div className="mb-3">
              <label className="form-label fw-semibold">N├║mero de Tel├®fono <span className="text-danger">*</span></label>
              <input className="form-control" placeholder="Ej: +506 8888-0000" value={form.enPhoneNumber} onChange={e => setForm(p => ({ ...p, enPhoneNumber: e.target.value }))} disabled={loading} maxLength={20} autoFocus />
            </div>
            <div className="mb-4">
              <label className="form-label fw-semibold">ID Adulto Mayor</label>
              <input type="number" className="form-control" placeholder="Opcional" value={form.idOlderAdult ?? ''} onChange={e => setForm(p => ({ ...p, idOlderAdult: e.target.value ? Number(e.target.value) : undefined }))} disabled={loading} />
            </div>
            <div className="d-flex gap-2 justify-content-end">
              <button type="button" className="btn btn-outline-secondary" onClick={() => navigate('/emergency-contacts')} disabled={loading}>Cancelar</button>
              <button type="submit" className="btn btn-primary" disabled={loading}>{loading ? <><span className="spinner-border spinner-border-sm me-2"></span>Guardando...</> : <><i className="bi bi-save me-2"></i>Guardar</>}</button>
            </div>
          </form>
        </div>
      </div>
    </div>
  );
}

import { useState, useEffect } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import { emergencyContactService } from '../../../services/emergencyContactService';
import type { UpdateEmergencyContactDto } from '../../../services/emergencyContactService';

export default function EditEmergencyContactPage() {
  const { id } = useParams<{ id: string }>();
  const [form, setForm] = useState<UpdateEmergencyContactDto>({ enPhoneNumber: '' });
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [error, setError] = useState('');
  const [success, setSuccess] = useState('');
  const navigate = useNavigate();

  useEffect(() => {
    if (!id) return;
    emergencyContactService.getById(Number(id)).then(d => { setForm({ enPhoneNumber: d.enPhoneNumber, idOlderAdult: d.idOlderAdult }); setLoading(false); })
      .catch(() => { setError('Error al cargar contacto'); setLoading(false); });
  }, [id]);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setSaving(true); setError(''); setSuccess('');
    try {
      await emergencyContactService.update(Number(id), form);
      setSuccess('Contacto actualizado exitosamente');
      setTimeout(() => navigate('/emergency-contacts'), 1500);
    } catch (err: any) {
      const msg = err?.response?.data?.message ?? err?.message ?? 'Error al actualizar';
      setError(Array.isArray(msg) ? msg.join(', ') : msg);
    } finally { setSaving(false); }
  };

  if (loading) return <div className="text-center py-5"><div className="spinner-border text-primary"></div></div>;

  return (
    <div className="container py-4" style={{ maxWidth: 500 }}>
      <div className="d-flex align-items-center mb-4 gap-3">
        <button className="btn btn-outline-secondary" onClick={() => navigate('/emergency-contacts')} type="button"><i className="bi bi-arrow-left me-1"></i>Regresar</button>
