      {success && <div className="alert alert-success"><i className="bi bi-check-circle-fill me-2"></i>{success}</div>}
      <div className="card shadow-sm">
        <div className="card-body">
          <form onSubmit={handleSubmit}>
            <div className="mb-3">
              <label className="form-label fw-semibold">N├║mero de Tel├®fono</label>
              <input className="form-control" value={form.enPhoneNumber ?? ''} onChange={e => setForm(p => ({ ...p, enPhoneNumber: e.target.value }))} disabled={saving} maxLength={20} />
            </div>
            <div className="mb-4">
              <label className="form-label fw-semibold">ID Adulto Mayor</label>
              <input type="number" className="form-control" value={form.idOlderAdult ?? ''} onChange={e => setForm(p => ({ ...p, idOlderAdult: e.target.value ? Number(e.target.value) : undefined }))} disabled={saving} />
            </div>
            <div className="d-flex gap-2 justify-content-end">
              <button type="button" className="btn btn-outline-secondary" onClick={() => navigate('/emergency-contacts')} disabled={saving}>Cancelar</button>
              <button type="submit" className="btn btn-warning" disabled={saving}>{saving ? <><span className="spinner-border spinner-border-sm me-2"></span>Guardando...</> : <><i className="bi bi-save me-2"></i>Actualizar</>}</button>
            </div>
          </form>
        </div>
      </div>
    </div>
  );
}

import { useState, useEffect } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import Swal from 'sweetalert2';
import { nursingService } from '../../../services/nursingService';
import type { NursingAppointment, UpdateAppointmentDto, AppointmentType, AppointmentPriority } from '../../../types/nursing';
import { 
  appointmentStatusLabels, 
  appointmentTypeLabels, 
  appointmentPriorityLabels,
  appointmentStatusColors,
  appointmentTypeColors,
  appointmentPriorityColors,
  mobilityLabels,
  qualityLevelLabels
} from '../../../types/nursing';

export default function AppointmentDetail() {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const [appointment, setAppointment] = useState<NursingAppointment | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string>('');
  const [isEditing, setIsEditing] = useState(false);
  const [editForm, setEditForm] = useState<UpdateAppointmentDto>({});

  useEffect(() => {
    if (id) {
      loadAppointmentDetails();
    }
  }, [id]);

  const loadAppointmentDetails = async () => {
    setLoading(true);
    setError('');
    try {
      const data = await nursingService.getNursingAppointments({ /* filtro por id si existe */ });
      const found = data.find(apt => apt.id === parseInt(id!));
      if (found) {
        setAppointment(found);
        setEditForm({
          saAppointmentDate: found.appointmentDate,
          saAppointmentType: found.appointmentType,
          saPriority: found.priority,
          saNotes: found.notes,
          saObservations: found.observations,
          saDurationMinutes: found.durationMinutes
        });
      } else {
        setError('Cita no encontrada');
      }
    } catch (err) {
      console.error('Error loading appointment:', err);
      setError('Error al cargar los detalles de la cita');
    } finally {
      setLoading(false);
    }
  };

  const handleCancelAppointment = async () => {
    const result = await Swal.fire({
      title: '┬┐Cancelar cita?',
      text: 'Esta acci├│n no se puede deshacer',
      icon: 'warning',
      input: 'textarea',
      inputLabel: 'Motivo de cancelaci├│n (opcional)',
      inputPlaceholder: 'Ingrese el motivo...',
      showCancelButton: true,
      confirmButtonColor: '#dc3545',
      cancelButtonColor: '#6c757d',
      confirmButtonText: 'S├¡, cancelar',
      cancelButtonText: 'No'
    });

    if (!result.isConfirmed) return;

    try {
      await nursingService.cancelAppointment(parseInt(id!), {
        cancellationReason: result.value || undefined
      });
      
      await Swal.fire({
        title: '┬íCita cancelada!',
        text: 'La cita ha sido cancelada exitosamente',
        icon: 'success',
        confirmButtonText: 'Aceptar',
        timer: 3000
      });

      navigate('/nursing');
    } catch (err) {
      console.error('Error cancelling appointment:', err);
      await Swal.fire({
        title: 'Error',
        text: 'No se pudo cancelar la cita. Intente nuevamente.',
        icon: 'error',
        confirmButtonText: 'Aceptar'
      });
    }
  };

  const handleUpdateAppointment = async () => {
    const result = await Swal.fire({
      title: '┬┐Guardar cambios?',
      text: 'Se actualizar├ín los datos de la cita',
      icon: 'question',
      showCancelButton: true,
      confirmButtonColor: '#0d6efd',
      cancelButtonColor: '#6c757d',
      confirmButtonText: 'S├¡, guardar',
      cancelButtonText: 'Cancelar'
    });

    if (!result.isConfirmed) return;

    try {
      await nursingService.updateAppointment(parseInt(id!), editForm);
      
      await Swal.fire({
        title: '┬íActualizado!',
        text: 'La cita ha sido actualizada exitosamente',
        icon: 'success',
        confirmButtonText: 'Aceptar',
        timer: 3000
      });

      setIsEditing(false);
      loadAppointmentDetails();
    } catch (err) {
      console.error('Error updating appointment:', err);
      await Swal.fire({
        title: 'Error',
        text: 'No se pudo actualizar la cita. Intente nuevamente.',
        icon: 'error',
        confirmButtonText: 'Aceptar'
      });
    }
  };

  const formatDateTime = (dateTime: string) => {
    const date = new Date(dateTime);
    return date.toLocaleString('es-ES', {
      day: '2-digit',
      month: '2-digit',
      year: 'numeric',
      hour: '2-digit',
      minute: '2-digit'
    });
  };

  // Convertir fecha de la BD a formato datetime-local (YYYY-MM-DDTHH:mm)
  const toLocalDateTimeString = (dateTime: string) => {
    const date = new Date(dateTime);
    const year = date.getFullYear();
    const month = String(date.getMonth() + 1).padStart(2, '0');
    const day = String(date.getDate()).padStart(2, '0');
    const hours = String(date.getHours()).padStart(2, '0');
    const minutes = String(date.getMinutes()).padStart(2, '0');
    return `${year}-${month}-${day}T${hours}:${minutes}`;
  };

  if (loading) {
    return (
      <div className="container py-4">
        <div className="d-flex justify-content-center">
          <div className="spinner-border text-primary" role="status">
            <span className="visually-hidden">Cargando...</span>
          </div>
        </div>
      </div>
    );
  }

  if (error || !appointment) {
    return (
      <div className="container py-4">
        <div className="alert alert-danger">
          <i className="bi bi-exclamation-triangle-fill me-2"></i>
          {error || 'No se pudo cargar la informaci├│n de la cita'}
        </div>
        <button className="btn btn-outline-secondary" onClick={() => navigate('/nursing')}>
          <i className="bi bi-arrow-left me-2"></i>
          Regresar
        </button>
      </div>
    );
  }

  return (
    <div className="container py-4">
      {/* Header */}
      <div className="d-flex justify-content-between align-items-center mb-4">
        <h3 className="mb-0">
          <i className="bi bi-calendar-event me-2 text-primary"></i>
          Detalles de la Cita
        </h3>
        <button 
          className="btn btn-secondary"
          onClick={() => navigate('/nursing')}
        >
          <i className="bi bi-arrow-left me-2"></i>
          Regresar
        </button>
      </div>

      {/* Estado de la cita */}
      <div className="row mb-4">
        <div className="col-12">
          <div className="card shadow-sm">
            <div className="card-body">
              <div className="row">
                <div className="col-md-3 text-center border-end">
                  <i className={`bi bi-circle-fill text-${appointmentStatusColors[appointment.status]} fs-1`}></i>
                  <h5 className="mt-2">Estado</h5>
                  <span className={`badge bg-${appointmentStatusColors[appointment.status]} fs-6`}>
                    {appointmentStatusLabels[appointment.status]}
                  </span>
                </div>
                <div className="col-md-3 text-center border-end">
                  <i className={`bi bi-clipboard-pulse text-${appointmentTypeColors[appointment.appointmentType]} fs-1`}></i>
                  <h5 className="mt-2">Tipo</h5>
                  <span className={`badge bg-${appointmentTypeColors[appointment.appointmentType]} fs-6`}>
                    {appointmentTypeLabels[appointment.appointmentType]}
                  </span>
                </div>
                <div className="col-md-3 text-center border-end">
                  <i className={`bi bi-exclamation-triangle text-${appointmentPriorityColors[appointment.priority]} fs-1`}></i>
                  <h5 className="mt-2">Prioridad</h5>
                  <span className={`badge bg-${appointmentPriorityColors[appointment.priority]} fs-6`}>
                    {appointmentPriorityLabels[appointment.priority]}
                  </span>
                </div>
                <div className="col-md-3 text-center">
                  <i className="bi bi-clock text-info fs-1"></i>
                  <h5 className="mt-2">Duraci├│n</h5>
                  <span className="badge bg-info fs-6">
                    {appointment.durationMinutes || 30} min
                  </span>
                </div>
              </div>
            </div>
          </div>
        </div>
      </div>

      {/* Informaci├│n del Paciente */}
      <div className="row mb-4">
        <div className="col-md-6">
          <div className="card shadow-sm h-100">
            <div className="card-header bg-primary bg-opacity-10">
              <h6 className="mb-0">
                <i className="bi bi-person-fill me-2"></i>
                Informaci├│n del Paciente
              </h6>
            </div>
            <div className="card-body">
              {appointment.patient ? (
                <>
                  <p className="mb-2">
                    <strong>Nombre:</strong><br />
                    {appointment.patient.name} {appointment.patient.firstLastName} {appointment.patient.secondLastName}
                  </p>
                  <p className="mb-0">
                    <strong>Identificaci├│n:</strong><br />
                    {appointment.patient.identification}
                  </p>
                </>
              ) : (
                <p className="text-muted mb-0">No hay informaci├│n del paciente</p>
              )}
            </div>
          </div>
        </div>

        <div className="col-md-6">
          <div className="card shadow-sm h-100">
            <div className="card-header bg-success bg-opacity-10">
              <h6 className="mb-0">
                <i className="bi bi-person-badge me-2"></i>
                Personal Asignado
              </h6>
            </div>
            <div className="card-body">
              {appointment.staff ? (
                <>
                  <p className="mb-2">
                    <strong>Nombre:</strong><br />
                    {appointment.staff.name} {appointment.staff.firstLastName} {appointment.staff.secondLastName}
                  </p>
                  <p className="mb-0">
                    <strong>Email:</strong><br />
                    {appointment.staff.email}
                  </p>
                </>
              ) : (
                <p className="text-muted mb-0">No hay personal asignado</p>
              )}
            </div>
          </div>
        </div>
      </div>

      {/* Detalles de la Cita */}
      <div className="card shadow-sm mb-4">
        <div className="card-header d-flex justify-content-between align-items-center">
          <h6 className="mb-0">
            <i className="bi bi-calendar-check me-2"></i>
            Detalles de la Cita
          </h6>
          {!isEditing && appointment.status !== 'completed' && appointment.status !== 'cancelled' && (
            <button 
              className="btn btn-sm btn-outline-primary"
              onClick={() => setIsEditing(true)}
            >
              <i className="bi bi-pencil me-1"></i>
              Editar
            </button>
          )}
        </div>
        <div className="card-body">
          {isEditing ? (
            <>
              <div className="row g-3 mb-3">
                <div className="col-md-6">
                  <label className="form-label"><strong>Fecha y Hora</strong></label>
                  <input
                    type="datetime-local"
                    className="form-control"
                    value={editForm.saAppointmentDate ? toLocalDateTimeString(editForm.saAppointmentDate) : ''}
                    onChange={(e) => setEditForm({ ...editForm, saAppointmentDate: e.target.value })}
                  />
                </div>
                <div className="col-md-3">
                  <label className="form-label"><strong>Tipo</strong></label>
                  <select
                    className="form-select"
                    value={editForm.saAppointmentType || ''}
                    onChange={(e) => setEditForm({ ...editForm, saAppointmentType: e.target.value as AppointmentType })}
                  >
                    <option value="checkup">Chequeo General</option>
                    <option value="evaluation">Evaluaci├│n</option>
                    <option value="therapy">Terapia</option>
                    <option value="follow_up">Seguimiento</option>
                    <option value="emergency">Emergencia</option>
                  </select>
                </div>
                <div className="col-md-3">
                  <label className="form-label"><strong>Prioridad</strong></label>
                  <select
                    className="form-select"
                    value={editForm.saPriority || ''}
                    onChange={(e) => setEditForm({ ...editForm, saPriority: e.target.value as AppointmentPriority })}
                  >
                    <option value="low">Baja</option>
                    <option value="medium">Media</option>
                    <option value="high">Alta</option>
                    <option value="urgent">Urgente</option>
                  </select>
                </div>
                <div className="col-md-12">
                  <label className="form-label"><strong>Notas</strong></label>
                  <textarea
                    className="form-control"
                    rows={3}
                    value={editForm.saNotes || ''}
                    onChange={(e) => setEditForm({ ...editForm, saNotes: e.target.value })}
                  />
                </div>
                <div className="col-md-12">
                  <label className="form-label"><strong>Observaciones</strong></label>
                  <textarea
                    className="form-control"
                    rows={2}
                    value={editForm.saObservations || ''}
                    onChange={(e) => setEditForm({ ...editForm, saObservations: e.target.value })}
                  />
                </div>
                <div className="col-md-12">
                  <label className="form-label"><strong>Duraci├│n (minutos)</strong></label>
                  <input
                    type="number"
                    className="form-control"
                    value={editForm.saDurationMinutes || 30}
                    onChange={(e) => setEditForm({ ...editForm, saDurationMinutes: parseInt(e.target.value) })}
                  />
                </div>
              </div>
              <div className="d-flex gap-2">
                <button className="btn btn-primary" onClick={handleUpdateAppointment}>
                  <i className="bi bi-check-lg me-1"></i>
                  Guardar Cambios
                </button>
                <button 
                  className="btn btn-secondary" 
                  onClick={() => {
                    setIsEditing(false);
                    setEditForm({
                      saAppointmentDate: appointment.appointmentDate,
                      saAppointmentType: appointment.appointmentType,
                      saPriority: appointment.priority,
                      saNotes: appointment.notes,
                      saObservations: appointment.observations,
                      saDurationMinutes: appointment.durationMinutes
                    });
                  }}
                >
                  <i className="bi bi-x-lg me-1"></i>
                  Cancelar
                </button>
              </div>
            </>
          ) : (
            <>
              <div className="row mb-3">
                <div className="col-md-6">
                  <p className="mb-2">
                    <strong>Fecha y Hora:</strong><br />
                    <i className="bi bi-calendar3 me-2"></i>
                    {formatDateTime(appointment.appointmentDate)}
                  </p>
                </div>
                <div className="col-md-6">
                  <p className="mb-2">
                    <strong>├ürea:</strong><br />
                    <i className="bi bi-hospital me-2"></i>
                    {appointment.area?.name || 'No especificada'}
                  </p>
                </div>
              </div>
              <div className="row mb-3">
                <div className="col-12">
                  <p className="mb-2">
                    <strong>Notas:</strong>
                  </p>
                  <div className="alert alert-info mb-0">
                    {appointment.notes || 'Sin notas'}
                  </div>
                </div>
              </div>
              {appointment.observations && (
                <div className="row">
                  <div className="col-12">
                    <p className="mb-2">
                      <strong>Observaciones:</strong>
                    </p>
                    <div className="alert alert-warning mb-0">
                      {appointment.observations}
                    </div>
                  </div>
                </div>
              )}
            </>
          )}
        </div>
      </div>

      {/* Registro de Enfermer├¡a (si existe) */}
      {appointment.nursingRecord && (
        <div className="card shadow-sm mb-4">
          <div className="card-header bg-success bg-opacity-10">
            <h6 className="mb-0">
              <i className="bi bi-clipboard2-pulse me-2"></i>
              Registro de Enfermer├¡a
            </h6>
          </div>
          <div className="card-body">
            <div className="row g-3">
              <div className="col-md-3">
                <strong>Temperatura:</strong>
                <p className="mb-0">{appointment.nursingRecord.temperature ? `${appointment.nursingRecord.temperature}┬░C` : 'N/A'}</p>
              </div>
              <div className="col-md-3">
                <strong>Presi├│n Arterial:</strong>
                <p className="mb-0">{appointment.nursingRecord.bloodPressure || 'N/A'}</p>
              </div>
              <div className="col-md-3">
                <strong>Frecuencia Card├¡aca:</strong>
                <p className="mb-0">{appointment.nursingRecord.heartRate ? `${appointment.nursingRecord.heartRate} bpm` : 'N/A'}</p>
              </div>
              <div className="col-md-3">
                <strong>Nivel de Dolor:</strong>
                <p className="mb-0">{appointment.nursingRecord.painLevel !== undefined ? `${appointment.nursingRecord.painLevel}/10` : 'N/A'}</p>
              </div>
              <div className="col-md-4">
                <strong>Movilidad:</strong>
                <p className="mb-0">{appointment.nursingRecord.mobility ? mobilityLabels[appointment.nursingRecord.mobility] : 'N/A'}</p>
              </div>
              <div className="col-md-4">
                <strong>Apetito:</strong>
                <p className="mb-0">{appointment.nursingRecord.appetite ? qualityLevelLabels[appointment.nursingRecord.appetite] : 'N/A'}</p>
              </div>
              <div className="col-md-4">
                <strong>Calidad del Sue├▒o:</strong>
                <p className="mb-0">{appointment.nursingRecord.sleepQuality ? qualityLevelLabels[appointment.nursingRecord.sleepQuality] : 'N/A'}</p>
              </div>
              {appointment.nursingRecord.notes && (
                <div className="col-12">
                  <strong>Notas del Registro:</strong>
                  <div className="alert alert-light mt-2 mb-0">
                    {appointment.nursingRecord.notes}
                  </div>
                </div>
              )}
            </div>
          </div>
        </div>
      )}

      {/* Siguiente Cita */}
      {appointment.nextAppointment && (
        <div className="alert alert-info">
          <i className="bi bi-calendar-plus me-2"></i>
          <strong>Pr├│xima cita programada:</strong> {formatDateTime(appointment.nextAppointment)}
        </div>
      )}

      {/* Acciones */}
      {appointment.status !== 'completed' && appointment.status !== 'cancelled' && (
        <div className="card shadow-sm">
          <div className="card-header bg-danger bg-opacity-10">
            <h6 className="mb-0 text-danger">
              <i className="bi bi-exclamation-triangle me-2"></i>
              Acciones de Riesgo
            </h6>
          </div>
          <div className="card-body">
            <button 
              className="btn btn-danger"
              onClick={handleCancelAppointment}
            >
              <i className="bi bi-x-circle me-2"></i>
              Cancelar Cita
            </button>
            <p className="text-muted small mt-2 mb-0">
              <i className="bi bi-info-circle me-1"></i>
              Esta acci├│n no se puede deshacer
            </p>
          </div>
        </div>
      )}
    </div>
  );
}

import { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { nursingService } from '../../../services/nursingService';
import type { NursingAppointment } from '../../../types/nursing';
import { appointmentStatusLabels, appointmentTypeLabels, appointmentStatusColors, appointmentPriorityColors } from '../../../types/nursing';

export default function AppointmentHistory() {
  const [appointments, setAppointments] = useState<NursingAppointment[]>([]);
  const [filteredAppointments, setFilteredAppointments] = useState<NursingAppointment[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string>('');
  const [filters, setFilters] = useState({
    status: '',
    type: '',
    search: '',
    dateFrom: '',
    dateTo: ''
  });
  const navigate = useNavigate();

  useEffect(() => {
    loadAppointments();
  }, []);

  useEffect(() => {
    applyFilters();
  }, [appointments, filters]);

  const loadAppointments = async () => {
    setLoading(true);
    setError('');
    try {
      const data = await nursingService.getNursingAppointments();
      const sortedData = data.sort((a: NursingAppointment, b: NursingAppointment) => 
        new Date(b.appointmentDate).getTime() - new Date(a.appointmentDate).getTime()
      );
      setAppointments(sortedData);
    } catch (err) {
      console.error('Error loading appointments:', err);
      setError('Error al cargar el historial de citas');
      setAppointments([]);
    } finally {
      setLoading(false);
    }
  };

  const applyFilters = () => {
    let filtered = [...appointments];

    if (filters.status) {
      filtered = filtered.filter(apt => apt.status === filters.status);
    }
    if (filters.type) {
      filtered = filtered.filter(apt => apt.appointmentType === filters.type);
    }
    if (filters.search) {
      const search = filters.search.toLowerCase();
      filtered = filtered.filter(apt => {
        const patientName = `${apt.patient?.name} ${apt.patient?.firstLastName}`.toLowerCase();
        const patientId = apt.patient?.identification || '';
        return patientName.includes(search) || patientId.includes(search);
      });
    }

    if (filters.dateFrom) {
      filtered = filtered.filter(apt => apt.appointmentDate >= filters.dateFrom);
    }
    if (filters.dateTo) {
      filtered = filtered.filter(apt => apt.appointmentDate <= filters.dateTo);
    }

    setFilteredAppointments(filtered);
  };

  const handleFilterChange = (field: string, value: string) => {
    setFilters(prev => ({ ...prev, [field]: value }));
  };

  const clearFilters = () => {
    setFilters({
      status: '',
      type: '',
      search: '',
      dateFrom: '',
      dateTo: ''
    });
  };

  const formatDateTime = (dateTime: string) => {
    const appointmentDate = new Date(dateTime);
    return appointmentDate.toLocaleString('es-ES', {
      day: '2-digit',
      month: '2-digit',
      year: 'numeric',
      hour: '2-digit',
      minute: '2-digit'
    });
  };

  if (loading) {
    return (
      <div className="container py-4">
        <div className="d-flex justify-content-center">
          <div className="spinner-border text-primary" role="status">
            <span className="visually-hidden">Cargando...</span>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="container py-4">
      <div className="d-flex justify-content-between align-items-center mb-4">
        <h3 className="mb-0">
          <i className="bi bi-clock-history me-2 text-info"></i>
          Historial de Citas
        </h3>
        <button 
          type="button" 
          className="btn btn-outline-secondary"
          onClick={() => navigate('/nursing')}
        >
          <i className="bi bi-arrow-left me-2"></i>
          Regresar
        </button>
      </div>

      {error && (
        <div className="alert alert-danger" role="alert">
          <i className="bi bi-exclamation-triangle-fill me-2"></i>
          {error}
        </div>
      )}

      {/* Filters */}
      <div className="card mb-4">
        <div className="card-header">
          <h6 className="mb-0">
            <i className="bi bi-funnel me-2"></i>
            Filtros
          </h6>
        </div>
        <div className="card-body">
          <div className="row g-3">
            <div className="col-md-3">
              <label className="form-label">Estado</label>
              <select 
                className="form-select"
                value={filters.status}
                onChange={(e) => handleFilterChange('status', e.target.value)}
              >
                <option value="">Todos los estados</option>
                <option value="scheduled">Programada</option>
                <option value="pending">Pendiente</option>
                <option value="in_progress">En progreso</option>
                <option value="completed">Completada</option>
                <option value="cancelled">Cancelada</option>
                <option value="no_show">No se present├│</option>
              </select>
            </div>

            <div className="col-md-3">
              <label className="form-label">Tipo</label>
              <select 
                className="form-select"
                value={filters.type}
                onChange={(e) => handleFilterChange('type', e.target.value)}
              >
                <option value="">Todos los tipos</option>
                <option value="checkup">Chequeo</option>
                <option value="evaluation">Evaluaci├│n</option>
                <option value="therapy">Terapia</option>
                <option value="follow_up">Seguimiento</option>
                <option value="emergency">Emergencia</option>
              </select>
            </div>

            <div className="col-md-3">
              <label className="form-label">Desde</label>
              <input 
                type="date"
                className="form-control"
                value={filters.dateFrom}
                onChange={(e) => handleFilterChange('dateFrom', e.target.value)}
              />
            </div>

            <div className="col-md-3">
              <label className="form-label">Hasta</label>
              <input 
                type="date"
                className="form-control"
                value={filters.dateTo}
                onChange={(e) => handleFilterChange('dateTo', e.target.value)}
              />
            </div>

            <div className="col-md-9">
              <label className="form-label">Buscar paciente</label>
              <input 
                type="text"
                className="form-control"
                placeholder="Buscar por nombre o identificaci├│n..."
                value={filters.search}
                onChange={(e) => handleFilterChange('search', e.target.value)}
              />
            </div>

            <div className="col-md-3 d-flex align-items-end">
              <button 
                type="button"
                className="btn btn-outline-secondary w-100"
                onClick={clearFilters}
              >
                <i className="bi bi-x-circle me-2"></i>
                Limpiar
              </button>
            </div>
          </div>
        </div>
      </div>

      {/* Results */}
      <div className="card">
        <div className="card-header d-flex justify-content-between align-items-center">
          <h6 className="mb-0">
            Resultados ({filteredAppointments.length} citas)
          </h6>
        </div>
        <div className="card-body">
          {filteredAppointments.length === 0 ? (
            <div className="text-center py-4 text-muted">
              <i className="bi bi-search fs-1 mb-3"></i>
              <p>No se encontraron citas con los filtros aplicados</p>
            </div>
          ) : (
            <div className="table-responsive">
              <table className="table table-hover">
                <thead className="table-light">
                  <tr>
                    <th>Fecha/Hora</th>
                    <th>Paciente</th>
                    <th>Tipo</th>
                    <th>Motivo</th>
                    <th>Estado</th>
                    <th>Observaciones</th>
                    <th>Acciones</th>
                  </tr>
                </thead>
                <tbody>
                  {filteredAppointments.map((appointment) => (
                    <tr key={appointment.id}>
                      <td>
                        <small>
                          {formatDateTime(appointment.appointmentDate)}
                        </small>
                      </td>
                      <td>
                        <div>
                          <strong>
                            {appointment.patient?.name} {appointment.patient?.firstLastName} {appointment.patient?.secondLastName}
                          </strong>
                          <br />
                          <small className="text-muted">
                            ID: {appointment.patient?.identification}
                          </small>
                        </div>
                      </td>
                      <td>
                        <span className={`badge bg-${appointmentPriorityColors[appointment.priority]}`}>
                          {appointmentTypeLabels[appointment.appointmentType]}
                        </span>
                      </td>
                      <td>
                        <span title={appointment.notes || ''}>
                          {appointment.notes && appointment.notes.length > 30 
                            ? appointment.notes.substring(0, 30) + '...'
                            : appointment.notes || '-'
                          }
                        </span>
                      </td>
                      <td>
                        <span className={`badge bg-${appointmentStatusColors[appointment.status]}`}>
                          {appointmentStatusLabels[appointment.status]}
                        </span>
                      </td>
                      <td>
                        {appointment.observations ? (
                          <span title={appointment.observations}>
                            {appointment.observations.length > 30 
                              ? appointment.observations.substring(0, 30) + '...'
                              : appointment.observations
                            }
                          </span>
                        ) : (
                          <span className="text-muted">-</span>
                        )}
                      </td>
                      <td>
                        <button
                          className="btn btn-sm btn-outline-primary"
                          onClick={() => {
                            const returnPath = '/nursing/appointments/history';
                            navigate(`/nursing/appointments/${appointment.id}/results?returnTo=${encodeURIComponent(returnPath)}`);
                          }}
                          disabled={appointment.status !== 'completed'}
                          title={appointment.status === 'completed' ? 'Ver resultados' : 'Cita no completada'}
                        >
                          <i className="bi bi-clipboard-data me-1"></i>
                          Ver Resultados
                        </button>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

import { useState, useEffect } from 'react';
import { useNavigate, useParams, useSearchParams } from 'react-router-dom';
import { nursingService } from '../../../services/nursingService';
import type { NursingAppointment } from '../../../types/nursing';
import { 
  appointmentStatusLabels, 
  appointmentTypeLabels,
  appointmentPriorityLabels,
  appointmentStatusColors,
  appointmentTypeColors,
  appointmentPriorityColors,
  mobilityLabels,
  qualityLevelLabels
} from '../../../types/nursing';

export default function AppointmentResults() {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const [searchParams] = useSearchParams();
  const [appointment, setAppointment] = useState<NursingAppointment | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string>('');
  
  // Leer el par├ímetro returnTo de la URL
  const returnPath = searchParams.get('returnTo') || '/nursing/appointments/history';

  useEffect(() => {
    if (id) {
      loadAppointmentResults();
    }
  }, [id]);

  const loadAppointmentResults = async () => {
    setLoading(true);
    setError('');
    try {
      // Obtener la cita
      const data = await nursingService.getNursingAppointments();
      const found = data.find(apt => apt.id === parseInt(id!));
      
      if (found) {
        // Si la cita no tiene nursingRecord incluido, intentar cargar los registros
        if (!found.nursingRecord) {
          try {
            const records = await nursingService.getNursingRecordsByAppointment(parseInt(id!));
            if (records && records.length > 0) {
              // Agregar el registro a la cita
              found.nursingRecord = records[0];
            }
          } catch (recordError) {
            console.warn('No se pudieron cargar los registros de enfermer├¡a:', recordError);
          }
        }
        
        setAppointment(found);
        
        if (!found.nursingRecord) {
          setError('Esta cita no tiene registro de enfermer├¡a');
        }
      } else {
        setError('Cita no encontrada');
      }
    } catch (err) {
      console.error('Error loading appointment results:', err);
      setError('Error al cargar los resultados de la cita');
    } finally {
      setLoading(false);
    }
  };

  const formatDateTime = (dateTime: string) => {
    const date = new Date(dateTime);
    return date.toLocaleString('es-ES', {
      day: '2-digit',
      month: '2-digit',
      year: 'numeric',
      hour: '2-digit',
      minute: '2-digit'
    });
  };

  const getPainLevelColor = (level: number) => {
    if (level <= 3) return 'success';
    if (level <= 6) return 'warning';
    return 'danger';
  };

  const getPainLevelText = (level: number) => {
    if (level === 0) return 'Sin dolor';
    if (level <= 3) return 'Dolor leve';
    if (level <= 6) return 'Dolor moderado';
    return 'Dolor severo';
  };

  if (loading) {
    return (
      <div className="container py-4">
        <div className="d-flex justify-content-center">
          <div className="spinner-border text-primary" role="status">
            <span className="visually-hidden">Cargando...</span>
          </div>
        </div>
      </div>
    );
  }

  if (error || !appointment || !appointment.nursingRecord) {
    return (
      <div className="container py-4">
        <div className="alert alert-danger">
          <i className="bi bi-exclamation-triangle-fill me-2"></i>
          {error || 'No hay resultados disponibles para esta cita'}
        </div>
        <button className="btn btn-outline-secondary" onClick={() => navigate(returnPath)}>
          <i className="bi bi-arrow-left me-2"></i>
          Regresar
        </button>
      </div>
    );
  }

  const record = appointment.nursingRecord;

  return (
    <div className="container py-4">
      {/* Header */}
      <div className="d-flex justify-content-between align-items-center mb-4">
        <h3 className="mb-0">
          <i className="bi bi-clipboard-data me-2 text-success"></i>
          Resultados de la Cita
        </h3>
        <div className="d-flex gap-2">
          <button 
            className="btn btn-outline-primary"
            onClick={() => window.print()}
          >
            <i className="bi bi-printer me-2"></i>
            Imprimir
          </button>
          <button 
            className="btn btn-outline-secondary"
            onClick={() => navigate(returnPath)}
          >
            <i className="bi bi-arrow-left me-2"></i>
            Regresar
          </button>
        </div>
      </div>

      {/* Informaci├│n General de la Cita */}
      <div className="card shadow-sm mb-4">
        <div className="card-header bg-primary bg-opacity-10">
          <h5 className="mb-0">
            <i className="bi bi-info-circle me-2"></i>
            Informaci├│n de la Cita
          </h5>
        </div>
        <div className="card-body">
          <div className="row g-4">
            <div className="col-md-6">
              <div className="border-start border-primary border-4 ps-3">
                <h6 className="text-muted mb-2">Paciente</h6>
                <p className="mb-1 fs-5 fw-bold">
                  {appointment.patient?.name} {appointment.patient?.firstLastName} {appointment.patient?.secondLastName}
                </p>
                <p className="text-muted mb-0">
                  <i className="bi bi-card-text me-2"></i>
                  ID: {appointment.patient?.identification}
                </p>
              </div>
            </div>
            <div className="col-md-6">
              <div className="border-start border-info border-4 ps-3">
                <h6 className="text-muted mb-2">Personal que Atendi├│</h6>
                <p className="mb-1 fs-5 fw-bold">
                  {appointment.staff?.name} {appointment.staff?.firstLastName} {appointment.staff?.secondLastName}
                </p>
                <p className="text-muted mb-0">
                  <i className="bi bi-envelope me-2"></i>
                  {appointment.staff?.email}
                </p>
              </div>
            </div>
          </div>

          <hr className="my-4" />

          <div className="row g-3">
            <div className="col-md-3">
              <p className="mb-1 text-muted small">Fecha y Hora</p>
              <p className="mb-0 fw-semibold">
                <i className="bi bi-calendar3 me-2 text-primary"></i>
                {formatDateTime(appointment.appointmentDate)}
              </p>
            </div>
            <div className="col-md-3">
              <p className="mb-1 text-muted small">Tipo de Cita</p>
              <span className={`badge bg-${appointmentTypeColors[appointment.appointmentType]} fs-6`}>
                {appointmentTypeLabels[appointment.appointmentType]}
              </span>
            </div>
            <div className="col-md-3">
              <p className="mb-1 text-muted small">Prioridad</p>
              <span className={`badge bg-${appointmentPriorityColors[appointment.priority]} fs-6`}>
                {appointmentPriorityLabels[appointment.priority]}
              </span>
            </div>
            <div className="col-md-3">
              <p className="mb-1 text-muted small">Estado</p>
              <span className={`badge bg-${appointmentStatusColors[appointment.status]} fs-6`}>
                {appointmentStatusLabels[appointment.status]}
              </span>
            </div>
          </div>

          {appointment.notes && (
            <>
              <hr className="my-3" />
              <div>
                <p className="mb-1 text-muted small">Motivo de la Cita</p>
                <div className="alert alert-light mb-0">
                  {appointment.notes}
                </div>
              </div>
            </>
          )}
        </div>
      </div>

      {/* Signos Vitales */}
      <div className="card shadow-sm mb-4">
        <div className="card-header bg-danger bg-opacity-10">
          <h5 className="mb-0">
            <i className="bi bi-heart-pulse me-2 text-danger"></i>
            Signos Vitales
          </h5>
        </div>
        <div className="card-body">
          <div className="row g-4">
            <div className="col-md-3 text-center">
              <div className="border rounded p-3 bg-light">
                <i className="bi bi-thermometer-half text-danger fs-1 mb-2"></i>
                <h6 className="text-muted mb-2">Temperatura</h6>
                <p className="fs-3 fw-bold mb-0">
                  {record.temperature ? `${record.temperature}┬░C` : 'N/A'}
                </p>
                {record.temperature && (
                  <small className={`badge ${record.temperature >= 37.5 ? 'bg-warning' : 'bg-success'} mt-2`}>
                    {record.temperature >= 37.5 ? 'Elevada' : 'Normal'}
                  </small>
                )}
              </div>
            </div>

            <div className="col-md-3 text-center">
              <div className="border rounded p-3 bg-light">
                <i className="bi bi-activity text-primary fs-1 mb-2"></i>
                <h6 className="text-muted mb-2">Presi├│n Arterial</h6>
                <p className="fs-3 fw-bold mb-0">
                  {record.bloodPressure || 'N/A'}
                </p>
                {record.bloodPressure && (
                  <small className="badge bg-info mt-2">mmHg</small>
                )}
              </div>
            </div>

            <div className="col-md-3 text-center">
              <div className="border rounded p-3 bg-light">
                <i className="bi bi-heartbeat text-danger fs-1 mb-2"></i>
                <h6 className="text-muted mb-2">Frecuencia Card├¡aca</h6>
                <p className="fs-3 fw-bold mb-0">
                  {record.heartRate ? `${record.heartRate}` : 'N/A'}
                </p>
                {record.heartRate && (
                  <small className="badge bg-info mt-2">bpm</small>
                )}
              </div>
            </div>

            <div className="col-md-3 text-center">
              <div className="border rounded p-3 bg-light">
                <i className={`bi bi-exclamation-circle text-${getPainLevelColor(record.painLevel || 0)} fs-1 mb-2`}></i>
                <h6 className="text-muted mb-2">Nivel de Dolor</h6>
                <p className="fs-3 fw-bold mb-0">
                  {record.painLevel !== undefined ? `${record.painLevel}/10` : 'N/A'}
                </p>
                {record.painLevel !== undefined && (
                  <small className={`badge bg-${getPainLevelColor(record.painLevel)} mt-2`}>
                    {getPainLevelText(record.painLevel)}
                  </small>
                )}
              </div>
            </div>
          </div>
        </div>
      </div>

      {/* Evaluaci├│n del Paciente */}
      <div className="card shadow-sm mb-4">
        <div className="card-header bg-success bg-opacity-10">
          <h5 className="mb-0">
            <i className="bi bi-person-check me-2 text-success"></i>
            Evaluaci├│n del Paciente
          </h5>
        </div>
        <div className="card-body">
          <div className="row g-4">
            <div className="col-md-4">
              <div className="d-flex align-items-center border-start border-success border-4 ps-3">
                <div className="flex-grow-1">
                  <h6 className="text-muted mb-1">Movilidad</h6>
                  <p className="mb-0 fs-5 fw-semibold">
                    {record.mobility ? mobilityLabels[record.mobility] : 'No registrado'}
                  </p>
                </div>
                <i className="bi bi-person-walking fs-1 text-success opacity-25"></i>
              </div>
            </div>

            <div className="col-md-4">
              <div className="d-flex align-items-center border-start border-warning border-4 ps-3">
                <div className="flex-grow-1">
                  <h6 className="text-muted mb-1">Apetito</h6>
                  <p className="mb-0 fs-5 fw-semibold">
                    {record.appetite ? qualityLevelLabels[record.appetite] : 'No registrado'}
                  </p>
                </div>
                <i className="bi bi-egg-fried fs-1 text-warning opacity-25"></i>
              </div>
            </div>

            <div className="col-md-4">
              <div className="d-flex align-items-center border-start border-info border-4 ps-3">
                <div className="flex-grow-1">
                  <h6 className="text-muted mb-1">Calidad del Sue├▒o</h6>
                  <p className="mb-0 fs-5 fw-semibold">
                    {record.sleepQuality ? qualityLevelLabels[record.sleepQuality] : 'No registrado'}
                  </p>
                </div>
                <i className="bi bi-moon-stars fs-1 text-info opacity-25"></i>
              </div>
            </div>
          </div>
        </div>
      </div>

      {/* Notas del Registro de Enfermer├¡a */}
      <div className="card shadow-sm mb-4">
        <div className="card-header bg-warning bg-opacity-10">
          <h5 className="mb-0">
            <i className="bi bi-journal-medical me-2 text-warning"></i>
            Notas del Registro de Enfermer├¡a
          </h5>
        </div>
        <div className="card-body">
          {record.notes ? (
            <div className="p-3 bg-light border-start border-warning border-4">
              <p className="mb-0" style={{ whiteSpace: 'pre-wrap' }}>
                {record.notes}
              </p>
            </div>
          ) : (
            <p className="text-muted mb-0">Sin notas registradas</p>
          )}
        </div>
      </div>

      {/* Observaciones Adicionales */}
      {appointment.observations && (
        <div className="card shadow-sm mb-4">
          <div className="card-header bg-info bg-opacity-10">
            <h5 className="mb-0">
              <i className="bi bi-chat-left-text me-2 text-info"></i>
              Observaciones Adicionales
            </h5>
          </div>
          <div className="card-body">
            <div className="p-3 bg-light border-start border-info border-4">
              <p className="mb-0" style={{ whiteSpace: 'pre-wrap' }}>
                {appointment.observations}
              </p>
            </div>
          </div>
        </div>
      )}

      {/* Pr├│xima Cita */}
      {appointment.nextAppointment && (
        <div className="alert alert-info shadow-sm">
          <div className="d-flex align-items-center">
            <i className="bi bi-calendar-plus fs-3 me-3"></i>
            <div>
              <h6 className="mb-1">Pr├│xima Cita Programada</h6>
              <p className="mb-0">{formatDateTime(appointment.nextAppointment)}</p>
            </div>
          </div>
        </div>
      )}

      {/* Informaci├│n de Registro */}
      <div className="card shadow-sm">
        <div className="card-body bg-light">
          <div className="row text-center">
            <div className="col-md-6">
              <small className="text-muted d-block mb-1">Fecha de Registro</small>
              <small className="fw-semibold">
                <i className="bi bi-calendar-check me-1"></i>
                {formatDateTime(record.createAt)}
              </small>
            </div>
            <div className="col-md-6">
              <small className="text-muted d-block mb-1">├ürea de Atenci├│n</small>
              <small className="fw-semibold">
                <i className="bi bi-hospital me-1"></i>
                {appointment.area?.name || 'No especificada'}
              </small>
            </div>
          </div>
        </div>
      </div>

      {/* Estilos de impresi├│n */}
      <style>{`
        @media print {
          .btn, .alert { display: none !important; }
          .card { border: 1px solid #dee2e6 !important; page-break-inside: avoid; }
          .card-header { background-color: #f8f9fa !important; }
        }
      `}</style>
    </div>
  );
}

import { useState, useEffect } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import Swal from 'sweetalert2';
import { nursingService } from '../../../services/nursingService';
import type { NursingAppointment, CompleteAppointmentDto, Mobility, QualityLevel } from '../../../types/nursing';
import { 
  appointmentStatusLabels, 
  appointmentTypeLabels,
  appointmentStatusColors
} from '../../../types/nursing';

export default function CompleteAppointment() {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const [appointment, setAppointment] = useState<NursingAppointment | null>(null);
  const [loading, setLoading] = useState(true);
  const [submitting, setSubmitting] = useState(false);
  const [error, setError] = useState<string>('');

  const [formData, setFormData] = useState<CompleteAppointmentDto>({
    nrTemperature: undefined,
    nrBloodPressure: '',
    nrHeartRate: undefined,
    nrPainLevel: 0,
    nrMobility: 'independent',
    nrAppetite: 'good',
    nrSleepQuality: 'good',
    nrNotes: ''
  });

  const [errors, setErrors] = useState<Record<string, string>>({});

  useEffect(() => {
    if (id) {
      loadAppointmentDetails();
    }
  }, [id]);

  const loadAppointmentDetails = async () => {
    setLoading(true);
    setError('');
    try {
      const data = await nursingService.getNursingAppointments();
      const found = data.find(apt => apt.id === parseInt(id!));
      if (found) {
        setAppointment(found);
        if (found.status === 'completed') {
          setError('Esta cita ya ha sido completada');
        } else if (found.status === 'cancelled') {
          setError('Esta cita ha sido cancelada');
        }
      } else {
        setError('Cita no encontrada');
      }
    } catch (err) {
      console.error('Error loading appointment:', err);
      setError('Error al cargar los detalles de la cita');
    } finally {
      setLoading(false);
    }
  };

  const handleInputChange = (field: keyof CompleteAppointmentDto, value: any) => {
    setFormData(prev => ({ ...prev, [field]: value }));
    if (errors[field]) {
      setErrors(prev => {
        const newErrors = { ...prev };
        delete newErrors[field];
        return newErrors;
      });
    }
  };

  const validateForm = (): boolean => {
    const newErrors: Record<string, string> = {};

    if (formData.nrTemperature && (formData.nrTemperature < 30 || formData.nrTemperature > 45)) {
      newErrors.nrTemperature = 'Temperatura fuera de rango v├ílido (30-45┬░C)';
    }

    if (formData.nrBloodPressure && !formData.nrBloodPressure.match(/^\d{2,3}\/\d{2,3}$/)) {
      newErrors.nrBloodPressure = 'Formato inv├ílido. Use formato: 120/80';
    }

    if (formData.nrHeartRate && (formData.nrHeartRate < 30 || formData.nrHeartRate > 200)) {
      newErrors.nrHeartRate = 'Frecuencia card├¡aca fuera de rango v├ílido (30-200 bpm)';
    }

    if (formData.nrPainLevel !== undefined && (formData.nrPainLevel < 0 || formData.nrPainLevel > 10)) {
      newErrors.nrPainLevel = 'Nivel de dolor debe estar entre 0 y 10';
    }

    if (!formData.nrNotes?.trim()) {
      newErrors.nrNotes = 'Las notas son obligatorias';
    }

    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();

    if (!validateForm()) {
      await Swal.fire({
        title: 'Errores en el formulario',
        text: 'Por favor corrige los errores antes de continuar',
        icon: 'error',
        confirmButtonText: 'Aceptar'
      });
      return;
    }

    const result = await Swal.fire({
      title: '┬┐Completar cita?',
      html: `
        <div class="text-start">
          <p><strong>Paciente:</strong> ${appointment?.patient?.name} ${appointment?.patient?.firstLastName}</p>
          <p><strong>Tipo:</strong> ${appointment ? appointmentTypeLabels[appointment.appointmentType] : ''}</p>
          <p class="text-muted small">Esta acci├│n marcar├í la cita como completada y guardar├í el registro de enfermer├¡a.</p>
        </div>
      `,
      icon: 'question',
      showCancelButton: true,
      confirmButtonColor: '#198754',
      cancelButtonColor: '#6c757d',
      confirmButtonText: 'S├¡, completar',
      cancelButtonText: 'Cancelar'
    });

    if (!result.isConfirmed) return;

    setSubmitting(true);

    try {
      await nursingService.completeAppointment(parseInt(id!), formData);
      
      await Swal.fire({
        title: '┬íCita completada!',
        text: 'La cita se ha completado y el registro de enfermer├¡a ha sido guardado',
        icon: 'success',
        confirmButtonText: 'Aceptar',
        timer: 3000,
        timerProgressBar: true
      });

      navigate('/nursing');
    } catch (err) {
      console.error('Error completing appointment:', err);
      await Swal.fire({
        title: 'Error',
        text: 'No se pudo completar la cita. Intente nuevamente.',
        icon: 'error',
        confirmButtonText: 'Aceptar'
      });
    } finally {
      setSubmitting(false);
    }
  };

  const formatDateTime = (dateTime: string) => {
    const date = new Date(dateTime);
    return date.toLocaleString('es-ES', {
      day: '2-digit',
      month: '2-digit',
      year: 'numeric',
      hour: '2-digit',
      minute: '2-digit'
    });
  };

  if (loading) {
    return (
      <div className="container py-4">
        <div className="d-flex justify-content-center">
          <div className="spinner-border text-primary" role="status">
            <span className="visually-hidden">Cargando...</span>
          </div>
        </div>
      </div>
    );
  }

  if (error || !appointment) {
    return (
      <div className="container py-4">
        <div className="alert alert-danger">
          <i className="bi bi-exclamation-triangle-fill me-2"></i>
          {error || 'No se pudo cargar la informaci├│n de la cita'}
        </div>
        <button className="btn btn-outline-secondary" onClick={() => navigate('/nursing')}>
          <i className="bi bi-arrow-left me-2"></i>
          Regresar
        </button>
      </div>
    );
  }

  return (
    <div className="container py-4">
      <form onSubmit={handleSubmit}>
        {/* Header */}
        <div className="d-flex justify-content-between align-items-center mb-4">
          <h3 className="mb-0">
            <i className="bi bi-check-circle me-2 text-success"></i>
            Completar Cita de Enfermer├¡a
          </h3>
          <button 
            type="button"
            className="btn btn-outline-secondary"
            onClick={() => navigate('/nursing')}
          >
            <i className="bi bi-arrow-left me-2"></i>
            Regresar
          </button>
        </div>

        {/* Informaci├│n de la Cita */}
        <div className="card shadow-sm mb-4">
          <div className="card-header bg-info bg-opacity-10">
            <h6 className="mb-0">
              <i className="bi bi-info-circle me-2"></i>
              Informaci├│n de la Cita
            </h6>
          </div>
          <div className="card-body">
            <div className="row">
              <div className="col-md-4">
                <p className="mb-2">
                  <strong>Paciente:</strong><br />
                  {appointment.patient?.name} {appointment.patient?.firstLastName} {appointment.patient?.secondLastName}
                </p>
                <p className="mb-0">
                  <strong>ID:</strong> {appointment.patient?.identification}
                </p>
              </div>
              <div className="col-md-4">
                <p className="mb-2">
                  <strong>Tipo de Cita:</strong><br />
                  <span className="badge bg-primary">
                    {appointmentTypeLabels[appointment.appointmentType]}
                  </span>
                </p>
                <p className="mb-0">
                  <strong>Estado:</strong>{' '}
                  <span className={`badge bg-${appointmentStatusColors[appointment.status]}`}>
                    {appointmentStatusLabels[appointment.status]}
                  </span>
                </p>
              </div>
              <div className="col-md-4">
                <p className="mb-2">
                  <strong>Fecha y Hora:</strong><br />
                  {formatDateTime(appointment.appointmentDate)}
                </p>
                <p className="mb-0">
                  <strong>├ürea:</strong> {appointment.area?.name || 'No especificada'}
                </p>
              </div>
            </div>
            {appointment.notes && (
              <div className="row mt-3">
                <div className="col-12">
                  <p className="mb-1"><strong>Notas de la cita:</strong></p>
                  <div className="alert alert-light mb-0">
                    {appointment.notes}
                  </div>
                </div>
              </div>
            )}
          </div>
        </div>

        {/* Signos Vitales */}
        <div className="card shadow-sm mb-4">
          <div className="card-header bg-danger bg-opacity-10">
            <h6 className="mb-0">
              <i className="bi bi-heart-pulse me-2"></i>
              Signos Vitales
            </h6>
          </div>
          <div className="card-body">
            <div className="row g-3">
              <div className="col-md-3">
                <label htmlFor="temperature" className="form-label">
                  Temperatura (┬░C)
                  <i className="bi bi-info-circle ms-1 text-muted" title="Rango normal: 36-37.5┬░C"></i>
                </label>
                <input
                  id="temperature"
                  type="number"
                  step="0.1"
                  className={`form-control ${errors.nrTemperature ? 'is-invalid' : ''}`}
                  value={formData.nrTemperature || ''}
                  onChange={(e) => handleInputChange('nrTemperature', e.target.value ? parseFloat(e.target.value) : undefined)}
                  placeholder="36.5"
                />
                {errors.nrTemperature && <div className="invalid-feedback">{errors.nrTemperature}</div>}
              </div>

              <div className="col-md-3">
                <label htmlFor="bloodPressure" className="form-label">
                  Presi├│n Arterial
                  <i className="bi bi-info-circle ms-1 text-muted" title="Formato: 120/80"></i>
                </label>
                <input
                  id="bloodPressure"
                  type="text"
                  className={`form-control ${errors.nrBloodPressure ? 'is-invalid' : ''}`}
                  value={formData.nrBloodPressure || ''}
                  onChange={(e) => handleInputChange('nrBloodPressure', e.target.value)}
                  placeholder="120/80"
                />
                {errors.nrBloodPressure && <div className="invalid-feedback">{errors.nrBloodPressure}</div>}
              </div>

              <div className="col-md-3">
                <label htmlFor="heartRate" className="form-label">
                  Frecuencia Card├¡aca (bpm)
                  <i className="bi bi-info-circle ms-1 text-muted" title="Rango normal: 60-100 bpm"></i>
                </label>
                <input
                  id="heartRate"
                  type="number"
                  className={`form-control ${errors.nrHeartRate ? 'is-invalid' : ''}`}
                  value={formData.nrHeartRate || ''}
                  onChange={(e) => handleInputChange('nrHeartRate', e.target.value ? parseInt(e.target.value) : undefined)}
                  placeholder="75"
                />
                {errors.nrHeartRate && <div className="invalid-feedback">{errors.nrHeartRate}</div>}
              </div>

              <div className="col-md-3">
                <label htmlFor="painLevel" className="form-label">
                  Nivel de Dolor (0-10) *
                </label>
                <input
                  id="painLevel"
                  type="range"
                  className="form-range"
                  min="0"
                  max="10"
                  value={formData.nrPainLevel || 0}
                  onChange={(e) => handleInputChange('nrPainLevel', parseInt(e.target.value))}
                />
                <div className="text-center">
                  <span className="badge bg-primary fs-6">{formData.nrPainLevel || 0}/10</span>
                </div>
                {errors.nrPainLevel && <div className="text-danger small">{errors.nrPainLevel}</div>}
              </div>
            </div>
          </div>
        </div>

        {/* Evaluaci├│n del Paciente */}
        <div className="card shadow-sm mb-4">
          <div className="card-header bg-primary bg-opacity-10">
            <h6 className="mb-0">
              <i className="bi bi-clipboard-check me-2"></i>
              Evaluaci├│n del Paciente
            </h6>
          </div>
          <div className="card-body">
            <div className="row g-3">
              <div className="col-md-4">
                <label htmlFor="mobility" className="form-label">Movilidad *</label>
                <select
                  id="mobility"
                  className="form-select"
                  value={formData.nrMobility || 'independent'}
                  onChange={(e) => handleInputChange('nrMobility', e.target.value as Mobility)}
                  required
                >
                  <option value="independent">Independiente</option>
                  <option value="assisted">Asistido</option>
                  <option value="bedridden">Postrado en cama</option>
                </select>
              </div>

              <div className="col-md-4">
                <label htmlFor="appetite" className="form-label">Apetito *</label>
                <select
                  id="appetite"
                  className="form-select"
                  value={formData.nrAppetite || 'good'}
                  onChange={(e) => handleInputChange('nrAppetite', e.target.value as QualityLevel)}
                  required
                >
                  <option value="good">Bueno</option>
                  <option value="regular">Regular</option>
                  <option value="poor">Malo</option>
                </select>
              </div>

              <div className="col-md-4">
                <label htmlFor="sleepQuality" className="form-label">Calidad del Sue├▒o *</label>
                <select
                  id="sleepQuality"
                  className="form-select"
                  value={formData.nrSleepQuality || 'good'}
                  onChange={(e) => handleInputChange('nrSleepQuality', e.target.value as QualityLevel)}
                  required
                >
                  <option value="good">Bueno</option>
                  <option value="regular">Regular</option>
                  <option value="poor">Malo</option>
                </select>
              </div>
            </div>
          </div>
        </div>

        {/* Notas del Registro */}
        <div className="card shadow-sm mb-4">
          <div className="card-header bg-warning bg-opacity-10">
            <h6 className="mb-0">
              <i className="bi bi-journal-text me-2"></i>
              Notas del Registro de Enfermer├¡a
            </h6>
          </div>
          <div className="card-body">
            <div className="mb-3">
              <label htmlFor="notes" className="form-label">
                Observaciones y Notas *
                <small className="text-muted ms-2">(Describa el estado general, observaciones importantes, recomendaciones)</small>
              </label>
              <textarea
                id="notes"
                className={`form-control ${errors.nrNotes ? 'is-invalid' : ''}`}
                rows={5}
                value={formData.nrNotes || ''}
                onChange={(e) => handleInputChange('nrNotes', e.target.value)}
                placeholder="Paciente en condiciones estables. Signos vitales normales. Continuar con tratamiento actual..."
                required
              />
              {errors.nrNotes && <div className="invalid-feedback">{errors.nrNotes}</div>}
            </div>
            <div className="alert alert-info mb-0">
              <i className="bi bi-lightbulb me-2"></i>
              <strong>Sugerencia:</strong> Incluya informaci├│n sobre el estado general del paciente, cualquier cambio observado, 
              reacciones a medicamentos, y recomendaciones para el cuidado continuo.
            </div>
          </div>
        </div>

        {/* Botones de Acci├│n */}
        <div className="d-flex gap-2">
          <button 
            type="submit" 
            className="btn btn-success btn-lg"
            style={{ backgroundColor: '#198754', borderColor: '#198754', color: 'white' }}
            onMouseEnter={(e) => e.currentTarget.style.backgroundColor = '#157347'}
            onMouseLeave={(e) => e.currentTarget.style.backgroundColor = '#198754'}
            disabled={submitting}
          >
            {submitting ? (
              <>
                <span className="spinner-border spinner-border-sm me-2" role="status" />
                Completando...
              </>
            ) : (
              <>
                <i className="bi bi-check-circle me-2"></i>
                Completar Cita
              </>
            )}
          </button>
          <button 
            type="button"
            className="btn btn-outline-secondary btn-lg"
            onClick={() => navigate('/nursing')}
            disabled={submitting}
          >
            <i className="bi bi-x-circle me-2"></i>
            Cancelar
          </button>
        </div>

        <div className="alert alert-warning mt-3">
          <i className="bi bi-exclamation-triangle me-2"></i>
          <strong>Importante:</strong> Una vez completada la cita, esta acci├│n no se puede deshacer. 
          Aseg├║rese de que toda la informaci├│n sea correcta antes de continuar.
        </div>
      </form>
    </div>
  );
}

import { useState, useEffect } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import { nursingService } from '../../../services/nursingService';
import type { NursingAppointment } from '../../../types/nursing';
import { 
  appointmentStatusLabels, 
  appointmentTypeLabels,
  appointmentPriorityLabels,
  appointmentStatusColors,
  appointmentTypeColors,
  appointmentPriorityColors
} from '../../../types/nursing';

export default function PatientAppointments() {
  const [appointments, setAppointments] = useState<NursingAppointment[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string>('');
  const navigate = useNavigate();
  const { patientId } = useParams<{ patientId: string }>();

  useEffect(() => {
    if (patientId) {
      loadAppointments();
    }
  }, [patientId]);

  const loadAppointments = async () => {
    if (!patientId) return;

    setLoading(true);
    setError('');
    
    try {
      const appointmentsData = await nursingService.getAppointmentsByPatientId(parseInt(patientId));

      const sortedAppointments = appointmentsData.sort((a: NursingAppointment, b: NursingAppointment) => 
        new Date(b.appointmentDate).getTime() - new Date(a.appointmentDate).getTime()
      );
      
      setAppointments(sortedAppointments);
    } catch (err) {
      console.error('Error loading patient appointments:', err);
      setError('Error al cargar las citas del paciente');
    } finally {
      setLoading(false);
    }
  };

  const formatDateTime = (dateTime: string) => {
    const appointmentDate = new Date(dateTime);
    return appointmentDate.toLocaleString('es-ES', {
      day: '2-digit',
      month: '2-digit',
      year: 'numeric',
      hour: '2-digit',
      minute: '2-digit'
    });
  };

  if (loading) {
    return (
      <div className="container py-4">
        <div className="d-flex justify-content-center">
          <div className="spinner-border text-primary" role="status">
            <span className="visually-hidden">Cargando...</span>
          </div>
        </div>
      </div>
    );
  }

  if (error) {
    return (
      <div className="container py-4">
        <div className="alert alert-danger" role="alert">
          <i className="bi bi-exclamation-triangle-fill me-2"></i>
          {error}
        </div>
        <button 
          type="button"
          className="btn btn-outline-secondary"
          onClick={() => navigate('/nursing')}
        >
          <i className="bi bi-arrow-left me-2"></i>
          Regresar
        </button>
      </div>
    );
  }

  return (
    <div className="container py-4">
      <div className="d-flex justify-content-between align-items-center mb-4">
        <h3 className="mb-0">
