              <Field label="Tensi├│n arterial" value={fmt(data.ta)} />
              <Field label="Peso" value={data.peso ? `${data.peso} kg` : ''} />
              <Field label="Talla" value={data.talla ? `${data.talla} cm` : ''} />
              <Field label="IMC" value={fmt(data.imc)} />
